// passwordPlaceholder returns a masked placeholder when an existing value is present.
func passwordPlaceholder(existing string) string {
	if existing != "" {
		return "••••••••"
	}
	return ""
}

// backendTypeLabel returns a human-readable label for a backend type.
func backendTypeLabel(backendType string) string {
	switch backendType {
	case "local":
		return "Local"
	case "sftp":
		return "SFTP"
	case "ftp":
		return "FTP"
	case "smb":
		return "SMB / CIFS"
	case "webdav":
		return "WebDAV"
	case "minio":
		return "MinIO / S3"
	case "git":
		return "Git"
	default:
		return fmt.Sprintf("Inconnu (%s)", backendType)
	}
}

